import{c as t,Q as n,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Agent Engineering: A New Discipline","description":"","frontmatter":{"title":"Agent Engineering: A New Discipline","authors":"LangChain Team","source":"https://blog.langchain.com/agent-engineering-a-new-discipline/","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2026-langchain-agent-engineering-new-discipline.md","filePath":"research/agent-harness/references/2026-langchain-agent-engineering-new-discipline.md","lastUpdated":1779796674000}'),i={name:"research/agent-harness/references/2026-langchain-agent-engineering-new-discipline.md"};function s(l,e,o,g,d,h){return n(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="agent-engineering-a-new-discipline" tabindex="-1">Agent Engineering: A New Discipline <a class="header-anchor" href="#agent-engineering-a-new-discipline" aria-label="Permalink to &quot;Agent Engineering: A New Discipline&quot;">​</a></h1><ul><li><strong>作者</strong>: LangChain Team</li><li><strong>平台</strong>: LangChain Blog</li><li><strong>URL</strong>: <a href="https://blog.langchain.com/agent-engineering-a-new-discipline/" target="_blank" rel="noreferrer">https://blog.langchain.com/agent-engineering-a-new-discipline/</a></li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority C — 定義 Agent Engineering 作為工程學科的宣言文章</li></ul><hr><h2 id="核心定義" tabindex="-1">核心定義 <a class="header-anchor" href="#核心定義" aria-label="Permalink to &quot;核心定義&quot;">​</a></h2><p><strong>Agent Engineering</strong> = 「將非確定性 LLM 系統迭代精煉為可靠生產體驗的過程」</p><hr><h2 id="與傳統軟體工程的根本差異" tabindex="-1">與傳統軟體工程的根本差異 <a class="header-anchor" href="#與傳統軟體工程的根本差異" aria-label="Permalink to &quot;與傳統軟體工程的根本差異&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>軟體工程</th><th>Agent Engineering</th></tr></thead><tbody><tr><td>輸入</td><td>大多數輸入已知且可預測</td><td>自然語言，任意輸入</td></tr><tr><td>測試</td><td>發布前完整測試</td><td>生產中學習，快速迭代</td></tr><tr><td>輸出</td><td>確定性輸出</td><td>非確定性，需統計視角</td></tr><tr><td>迭代周期</td><td>季度發行</td><td>快速 Build-Ship-Observe</td></tr></tbody></table><hr><h2 id="工程循環" tabindex="-1">工程循環 <a class="header-anchor" href="#工程循環" aria-label="Permalink to &quot;工程循環&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Build → Test → Ship → Observe → Refine → Repeat</span></span></code></pre></div><p>關鍵轉變：放棄「發布前完美」，改為快速發行 + 生產學習。</p><hr><h2 id="跨職能技能要求" tabindex="-1">跨職能技能要求 <a class="header-anchor" href="#跨職能技能要求" aria-label="Permalink to &quot;跨職能技能要求&quot;">​</a></h2><p>Agent Engineering 需要三種能力的整合：</p><ol><li><strong>Product Thinking</strong>: 提示工程、workflow 設計、評估標準定義</li><li><strong>Engineering</strong>: 工具整合、UI、durable runtime 建構</li><li><strong>Data Science</strong>: 評估、A/B 測試、monitoring</li></ol><hr><h2 id="實際案例" tabindex="-1">實際案例 <a class="header-anchor" href="#實際案例" aria-label="Permalink to &quot;實際案例&quot;">​</a></h2><ul><li><strong>Clay</strong>: prospect 研究 agent（B2B sales 自動化）</li><li><strong>LinkedIn</strong>: 招聘 agent（候選人匹配）</li><li><strong>Cloudflare</strong>: 候選人排名 agent（HR 自動化）</li></ul><hr><h2 id="核心洞見" tabindex="-1">核心洞見 <a class="header-anchor" href="#核心洞見" aria-label="Permalink to &quot;核心洞見&quot;">​</a></h2><ol><li><strong>非確定性是根本</strong>: LLM 的不可預測性不是 bug，是 feature；harness 需要統計性管理</li><li><strong>自然語言的不可預測性</strong>: 用戶可以輸入任何東西，打破傳統軟體的輸入/輸出假設</li><li><strong>系統化追蹤的必要性</strong>: 每個決策要被記錄，大規模評估，快速迭代</li><li><strong>跨職能本質</strong>: 沒有單一角色能獨立完成 agent 工程</li></ol><hr><h2 id="與本-workspace-的關聯" tabindex="-1">與本 Workspace 的關聯 <a class="header-anchor" href="#與本-workspace-的關聯" aria-label="Permalink to &quot;與本 Workspace 的關聯&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent Engineering 要素</th><th>Workspace 的對應</th></tr></thead><tbody><tr><td>Build</td><td>implementer agent + core.md 實作習慣</td></tr><tr><td>Test</td><td>test-writer agent + healthcheck.sh</td></tr><tr><td>Observe</td><td>Auto Memory + retro skill</td></tr><tr><td>Refine</td><td>Ratchet 原則 + FRAMEWORK.md 更新</td></tr><tr><td>跨職能協作</td><td>多 agent 分工（researcher/implementer/reviewer）</td></tr></tbody></table>',25)])])}const u=t(i,[["render",s]]);export{p as __pageData,u as default};
